def cache_db_query(key_prefix, ttl=300):
    """
    Decorator for caching database query results.
    Assumes the decorated function returns a dict or list that can be JSON serialized.
    """
    def decorator(func):
        def wrapper(*args, **kwargs):
            cache_key = f"{key_prefix}:{func.__name__}:{json.dumps(args)}:{json.dumps(kwargs)}"
            
            cached_data = memcached_client.get(cache_key)
            if cached_data:
                app.logger.info(f"Cache HIT for DB query: {cache_key}")
                try:
                    return json.loads(cached_data)
                except json.JSONDecodeError:
                    app.logger.error(f"Failed to decode cached data for {cache_key}. Re-fetching.")
                    pass # Fall through to original function

            app.logger.info(f"Cache MISS for DB query: {cache_key}. Executing function.")
            result = func(*args, **kwargs)
            
            try:
                memcached_client.set(cache_key, json.dumps(result), expire=ttl)
            except Exception as e:
                app.logger.error(f"Failed to set cache for {cache_key}: {e}")
            
            return result
        return wrapper
    return decorator

def cache_api_response(ttl=60):
    """
    Decorator for caching API responses based on the request path and query parameters.
    Assumes the decorated function returns a Flask response object or data suitable for jsonify.
    """
    def decorator(func):
        def wrapper(*args, **kwargs):
            # Generate a cache key based on the request path and query string
            cache_key = f"api:{request.path}:{sorted(request.args.items())}"
            
            cached_response = memcached_client.get(cache_key)
            if cached_response:
                app.logger.info(f"Cache HIT for API response: {cache_key}")
                try:
                    # Assuming cached_response is a JSON string of the original jsonify output
                    return jsonify(json.loads(cached_response))
                except json.JSONDecodeError:
                    app.logger.error(f"Failed to decode cached API response for {cache_key}. Re-fetching.")
                    pass # Fall through to original function

            app.logger.info(f"Cache MISS for API response: {cache_key}. Executing function.")
            
            # Execute the original function to get the response data
            response_data = func(*args, **kwargs)
            
            # If the function returns a Flask Response object, we need to extract its JSON payload
            if isinstance(response_data, tuple) and isinstance(response_data[0], dict): # Example: (data, status_code)
                 data_to_cache = response_data[0]
            elif isinstance(response_data, dict) or isinstance(response_data, list): # Direct data
                 data_to_cache = response_data
            else:
                 # If it's not directly JSON-serializable data, log and don't cache
                 app.logger.warning(f"API response for {cache_key} is not directly serializable for caching. Type: {type(response_data)}")
                 return jsonify(response_data) # Return original, uncached

            try:
                memcached_client.set(cache_key, json.dumps(data_to_cache), expire=ttl)
            except Exception as e:
                app.logger.error(f"Failed to set cache for API response {cache_key}: {e}")
            
            # Return the actual Flask response
            if isinstance(response_data, tuple):
                return jsonify(response_data[0]), response_data[1] # Handle (data, status_code)
            return jsonify(response_data)
        return wrapper
    return decorator

